def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        total_power_sum = 0
        for j in range(1, 20):
            base_factor = (0.7 + 0.05 * (j % 5)) * (1 / (j**1.5))
            power_component = base_factor * (ratio ** j)
            if j % 4 == 0:
                power_component *= 1.3
            elif j % 6 == 0:
                power_component *= 0.9
            total_power_sum += power_component
        score += total_power_sum
        remaining = capacity - item
        if remaining < 0.02 * capacity:
            score *= 3.0
        elif remaining < 0.07 * capacity:
            score *= 2.0
        elif remaining < 0.15 * capacity:
            score *= 1.3
        elif remaining < 0.3 * capacity:
            score *= 0.85
        else:
            score *= 0.5
        mod_vals = {3: int(capacity) % 3 == 0, 4: int(capacity) % 4 == 0, 5: int(capacity) % 5 == 0, 7: int(capacity) % 7 == 0}
        if mod_vals[3] and mod_vals[5] and mod_vals[7]:
            score -= 0.15 * (capacity / 12)
        elif mod_vals[3] and mod_vals[4]:
            score -= 0.1 * (capacity / 9)
        elif mod_vals[5] and mod_vals[7]:
            score -= 0.16 * (capacity / 14)
        elif mod_vals[3]:
            score -= 0.06 * (capacity / 11)
        elif mod_vals[4]:
            score -= 0.08 * (capacity / 13)
        elif mod_vals[5]:
            score -= 0.09 * (capacity / 17)
        elif mod_vals[7]:
            score -= 0.07 * (capacity / 19)
        else:
            score -= 0.04 * (capacity / 22)
        penalty = 0
        for k in range(1, 8):
            diff = abs(capacity - item * k)
            threshold = 0.012 * capacity * k
            if diff < threshold:
                penalty += 0.3 * k
            elif diff < 1.5 * threshold:
                penalty += 0.15 * k
            elif diff < 2.5 * threshold:
                penalty -= 0.07 * k
            else:
                penalty -= 0.12 * k
        score += penalty
        adjust = 1
        for m in range(1, 5):
            check_val = capacity / m
            if abs(check_val - item) < 0.025 * check_val:
                adjust *= (1 + 0.07 * m)
            else:
                adjust *= (1 - 0.03 * m)
        score *= max(0.1, adjust)
        if score < 0:
            score = 0
        if score > 2.0:
            for p in range(1, 6):
                if abs((capacity / p) - item) < 0.015 * (capacity / p):
                    score *= (1 + 0.08 * p)
        priorities[i] = score
    return priorities
